"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[50],{51442:(i,e,n)=>{n.r(e),n.d(e,{data:()=>s});const s={key:"v-0332d8ad",path:"/leaflet/guide/%E7%A4%BA%E4%BE%8B%E4%BB%A3%E7%A0%81/Leaflet%E5%8A%A0%E8%BD%BD%E7%AC%AC%E4%B8%89%E6%96%B9%E5%9C%B0%E5%9B%BE-%E7%99%BE%E5%BA%A6%E5%9C%B0%E5%9B%BE(%E6%8F%92%E4%BB%B6).html",title:"Leaflet加载第三方地图-百度地图(插件)",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[],git:{updatedTime:1653445943e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"leaflet/guide/示例代码/Leaflet加载第三方地图-百度地图(插件).md"}},87794:(i,e,n)=>{n.r(e),n.d(e,{default:()=>d});const s=(0,n(57293).uE)('<p>[TOC]</p><h1 id="leaflet加载第三方地图-百度地图-插件" tabindex="-1"><a class="header-anchor" href="#leaflet加载第三方地图-百度地图-插件" aria-hidden="true">#</a> Leaflet加载第三方地图-百度地图(插件)</h1><p>把百度地图提供的图层封装成插件，统一调用</p><p>效果如下</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202110291635270.png" alt="img"><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>L.TileProviders.Base.js代码如下</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>//定义插件\nL.TileProviders = {};\n\nL.TileProviders.Base = L.Class.extend({\n    maps: {},\n    options: {},\n    crs: L.CRS.EPSG3857,\n    initialize(maps, options) {\n        this.maps = L.Util.extend(this.maps, maps || {});\n        this.options = L.Util.extend(this.options, options || {});\n    },\n    /**\n     * 获取图层\n     * @param {string} type 图层类型\n     * @param {Object} options TileLayer Options\n     */\n    getLayer(type, options) {\n        var map = this.maps[type];\n        var url = map.url;\n        options = L.Util.extend(this.options, options || {});\n        options.key = map.key ? map.key : options.key;\n        return L.tileLayer(url, options);\n    }\n});\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>L.TileProvider.BaiDu.js代码如下</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>//定义坐标系\nif (L.Proj) {\n    L.CRS.Baidu = new L.Proj.CRS(&#39;EPSG:900913&#39;, &#39;+proj=merc +a=6378206 +b=6356584.314245179 +lat_ts=0.0 +lon_0=0.0 +x_0=0 +y_0=0 +k=1.0 +units=m +nadgrids=@null +wktext  +no_defs&#39;, {\n        resolutions: function () {\n            var level = 19\n            var res = [];\n            res[0] = Math.pow(2, 18);\n            for (var i = 1; i &lt; level; i++) {\n                res[i] = Math.pow(2, (18 - i))\n            }\n            return res;\n        }(),\n        origin: [0, 0],\n        bounds: L.bounds([20037508.342789244, 0], [0, 20037508.342789244])\n    });\n}\n\n\n/**\n * 百度图层提供者\n * @param {Object} maps \n * @param {Object} options\n */\n L.TileProviders.BaiDu = L.TileProviders.Base.extend({\n    maps: {\n        Normal_Map: {\n            url: &quot;//online{s}.map.bdimg.com/onlinelabel/?qt=tile&amp;x={x}&amp;y={y}&amp;z={z}&amp;styles=pl&amp;scaler=1&amp;p=1&quot;,\n            name: &quot;矢量地图&quot;\n        },\n        Satellite_Map: {\n            url: &quot;//shangetu{s}.map.bdimg.com/it/u=x={x};y={y};z={z};v=009;type=sate&amp;fm=46&quot;,\n            name: &quot;影像地图&quot;\n        },\n        Satellite_Annotion: {\n            url: &quot;//online{s}.map.bdimg.com/tile/?qt=tile&amp;x={x}&amp;y={y}&amp;z={z}&amp;styles=sl&amp;v=020&quot;,\n            name: &quot;影像注记&quot;\n        }\n    },\n    options: {\n        subdomains: &quot;0123456789&quot;,\n        tms:true\n\n    },\n    crs:L.CRS.Baidu\n});\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>index.html代码如下</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;!DOCTYPE html&gt;\n&lt;html lang=&quot;en&quot;&gt;\n\n&lt;head&gt;\n    &lt;meta charset=&quot;UTF-8&quot;&gt;\n    &lt;meta http-equiv=&quot;X-UA-Compatible&quot; content=&quot;IE=edge&quot;&gt;\n    &lt;meta name=&quot;viewport&quot; content=&quot;width=device-width, initial-scale=1.0&quot;&gt;\n    &lt;!-- leaflet样式 --&gt;\n    &lt;link href=&quot;https://unpkg.com/leaflet@1.7.1/dist/leaflet.css&quot; rel=&quot;stylesheet&quot; /&gt;\n    &lt;!-- leaflet类库 --&gt;\n    &lt;script src=&quot;https://unpkg.com/leaflet@1.7.1/dist/leaflet-src.js&quot;&gt;&lt;/script&gt;\n    &lt;!-- proj4 --&gt;\n    &lt;script src=&quot;https://unpkg.com/proj4@2.7.5/dist/proj4.js&quot;&gt;&lt;/script&gt;\n    &lt;!-- proj4leaflet --&gt;\n    &lt;script src=&quot;https://unpkg.com/proj4leaflet@1.0.2/src/proj4leaflet.js&quot;&gt;&lt;/script&gt;\n    &lt;!-- 插件 --&gt;\n    &lt;script src=&quot;L.TileProviders.Base.js&quot;&gt;&lt;/script&gt;\n    &lt;script src=&quot;L.TileProvider.BaiDu.js&quot;&gt;&lt;/script&gt;\n    &lt;title&gt;Leaflet加载第三方地图-百度地图(插件)&lt;/title&gt;\n    &lt;style&gt;\n        html,\n        body,\n        #map {\n            width: 100%;\n            height: 100%;\n            margin: 0;\n            padding: 0;\n        }\n    &lt;/style&gt;\n&lt;/head&gt;\n\n&lt;body&gt;\n    &lt;div id=&quot;map&quot;&gt;\n\n    &lt;/div&gt;\n    &lt;script&gt;\n        //初始化插件\n        var tileProviders = new L.TileProviders.BaiDu();\n\n        //地图初始化\n        var map = L.map(&quot;map&quot;, { crs: tileProviders.crs });\n        console.log(map);\n        map.setView([28.46337852800008, 120.967045726], 6);\n\n        //创建图层\n        var baseLayers = {\n            &quot;矢量地图&quot;: tileProviders.getLayer(&quot;Normal_Map&quot;).addTo(map),\n            &quot;影像地图&quot;: tileProviders.getLayer(&quot;Satellite_Map&quot;)\n        }\n\n        var annotionLayers = {\n            &quot;影像注记&quot;: tileProviders.getLayer(&quot;Satellite_Annotion&quot;)\n        }\n\n        //创建图层管理控件\n        L.control.layers(baseLayers, annotionLayers).addTo(map);\n    &lt;/script&gt;\n&lt;/body&gt;\n\n&lt;/html&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>源码地址</p><p>链接：https://pan.baidu.com/s/1qlrvJLLigKzwbUoCtsDeHQ 提取码：swxs</p>',16),l={},d=(0,n(63243).Z)(l,[["render",function(i,e){return s}]])},63243:(i,e)=>{e.Z=(i,e)=>{const n=i.__vccOpts||i;for(const[i,s]of e)n[i]=s;return n}}}]);